function presGetCodigo(cliente, n) {
  // SAV-[3letras cliente]-[año]-[nro 3 dígitos]
  const siglas = cliente.replace(/[^A-Za-z ]/g,'').split(' ').map(w=>w[0]).join('').slice(0,3).toUpperCase();
  const anio = new Date().getFullYear().toString().slice(-2);
  return `SAV-${siglas}-${anio}-${String(n).padStart(3,'0')}`;
}

function fmtNum(n) {
  return n.toLocaleString('es-ES', {minimumFractionDigits:2, maximumFractionDigits:2});
}

function renderPresLista(cliente) {
  presCurrentCliente = cliente || presCurrentCliente;
  const lista = presupuestosData[presCurrentCliente] || [];
  const tbody = document.getElementById('pres-tbody');
  if (!tbody) return;

  const estadoMap = { pendiente:'pendiente', aprobado:'aprobado', rechazado:'rechazado', enviado:'enviado' };
  const estadoLabel = { pendiente:'Pendiente', aprobado:'Aprobado', rechazado:'Rechazado', enviado:'Enviado' };

  tbody.innerHTML = lista.map((p, i) => {
    const totalCoste = p.partidas.reduce((s,x) => s + x.qty * x.pUnit, 0);
    const totalCliente = p.partidas.reduce((s,x) => s + x.qty * x.pUnit * (1 + x.margen/100), 0);
    const mo = totalCliente - totalCoste;
    const est = estadoMap[p.estado] || 'pendiente';
    return `<tr class="pres-row" style="cursor:pointer;" onclick="presVerDetalle(${i})">
      <td><span class="mono" style="font-size:12px;color:var(--text-2);">${p.codigo}</span></td>
      <td style="max-width:240px;">
        <div style="font-weight:500;font-size:13px;">${p.descripcion}</div>
        <div style="font-size:11px;color:var(--text-3);margin-top:2px;">${[...new Set((p.partidas||[]).map(x=>x.proveedor).filter(Boolean))].join(' · ') || ''}</div>
      </td>
      <td style="font-size:12px;color:var(--text-2);">${p.tipo}</td>
      <td class="num" style="font-size:13px;font-weight:600;">€${fmtNum(totalCliente)}</td>
      <td class="num" style="font-size:13px;color:var(--text-2);">€${fmtNum(totalCoste)}</td>
      <td class="num" style="font-size:13px;font-weight:600;color:var(--accent-2);">€${fmtNum(mo)}</td>
      <td style="font-size:12px;color:var(--text-2);">${p.fecha}</td>
      <td><span class="badge ${est}"><span class="badge-dot"></span>${estadoLabel[est]}</span></td>
      <td><button class="btn btn-ghost btn-sm" onclick="event.stopPropagation();presVerDetalle(${i})">Ver →</button></td>
    </tr>`;
  }).join('');

  const lbl = document.getElementById('pres-list-label');
  if (lbl) lbl.textContent = lista.length + ' presupuesto' + (lista.length !== 1 ? 's' : '');
}

function presVerDetalle(i) {
  presCurrentIndex = i;
  const p = presupuestosData[presCurrentCliente][i];
  presPartidas = p.partidas.map(x => ({...x})); // deep copy

  // Fill header fields
  document.getElementById('pres-codigo-display').textContent = p.codigo;
  document.getElementById('pres-tipo-display').textContent = p.tipo;
  document.getElementById('pres-instalacion-display').textContent = p.instalacion;
  document.getElementById('pres-fecha-display').textContent = p.fecha;
  document.getElementById('pres-descripcion').textContent = p.descripcion;
  document.getElementById('pres-fpago').textContent = p.fpago;
  document.getElementById('pres-plazo').textContent = p.plazo;
  document.getElementById('pres-banco').textContent = p.banco;

  // Cliente info from current client
  const c = clientes.find(x => x.nombre === presCurrentCliente);
  if (c) {
    document.getElementById('pres-cliente-nombre').textContent = c.nombre;
    document.getElementById('pres-cliente-cif').textContent = 'CIF: ' + c.cif;
  }

  // Estado
  const estadoSel = document.getElementById('pres-estado-sel');
  if (estadoSel) estadoSel.value = p.estado;
  presUpdateEstadoBadge(p.estado);

  renderPresPartidas();
  presRecalcTotales();

  document.getElementById('pres-list-view').style.display = 'none';
  document.getElementById('pres-detail-view').style.display = 'block';
}

function presNuevo() {
  presCurrentIndex = null;
  const lista = presupuestosData[presCurrentCliente] || [];
  const nextN = lista.length + 1;
  const codigo = presGetCodigo(presCurrentCliente, nextN);

  presPartidas = [
    { nro:1, desc:'', ud:'ud', qty:1, pUnit:0, margen:20, costeUnit:0, proveedor:'' }
  ];

  document.getElementById('pres-codigo-display').textContent = codigo;
  document.getElementById('pres-tipo-display').textContent = 'Servicio';
  document.getElementById('pres-instalacion-display').textContent = 'Instalación';
  document.getElementById('pres-fecha-display').textContent = new Date().toLocaleDateString('es-ES');
  document.getElementById('pres-descripcion').textContent = 'Descripción de los trabajos';
  document.getElementById('pres-fpago').textContent = 'Transferencia bancaria';
  document.getElementById('pres-plazo').textContent = '60 días fecha factura';
  document.getElementById('pres-banco').textContent = 'Bankinter · ES90 0128 6192 0901 0534 2136';

  const c = clientes.find(x => x.nombre === presCurrentCliente);
  if (c) {
    document.getElementById('pres-cliente-nombre').textContent = c.nombre;
    document.getElementById('pres-cliente-cif').textContent = 'CIF: ' + c.cif;
  }

  const estadoSel = document.getElementById('pres-estado-sel');
  if (estadoSel) estadoSel.value = 'pendiente';
  presUpdateEstadoBadge('pendiente');

  renderPresPartidas();
  presRecalcTotales();

  document.getElementById('pres-list-view').style.display = 'none';
  document.getElementById('pres-detail-view').style.display = 'block';
}

function presVolver() {
  document.getElementById('pres-detail-view').style.display = 'none';
  document.getElementById('pres-list-view').style.display = 'block';
}

function presUpdateEstadoBadge(estado) {
  const labelMap = { pendiente:'Pendiente', aprobado:'Aprobado', rechazado:'Rechazado', enviado:'Enviado' };
  const colorMap = { pendiente:'background:var(--warn-light);color:var(--warn);', aprobado:'background:var(--accent-2-light);color:var(--accent-2);', rechazado:'background:#F3F4F6;color:#6B7280;', enviado:'background:var(--accent-light);color:var(--accent);' };
  const badge = document.getElementById('pres-estado-badge');
  if (badge) { badge.textContent = labelMap[estado] || estado; badge.style.cssText = colorMap[estado] || ''; badge.style.fontSize = '11px'; badge.style.fontWeight = '500'; badge.style.padding = '2px 8px'; badge.style.borderRadius = '4px'; }
}

function presSetEstado(val) { presUpdateEstadoBadge(val); }

function renderPresPartidas() {
  const tbody = document.getElementById('pres-partidas-tbody');
  if (!tbody) return;
  tbody.innerHTML = presPartidas.map((p, i) => {
    const pUnitCliente = p.pUnit;
    const totalCliente = p.qty * pUnitCliente;
    const costeUnit = p.costeUnit || 0;
    const totalProv = p.qty * costeUnit;
    const beneficio = totalCliente - totalProv;
    const pctMO = totalCliente > 0 ? ((beneficio / totalCliente) * 100) : 0;
    return `<tr class="pres-row" id="prow-${i}" style="border-bottom:1px solid var(--border);">
      <td style="padding:6px 10px;color:var(--text-3);font-size:12px;text-align:center;">${p.nro}</td>
      <td style="padding:4px 8px;">
        <input class="pres-desc-input" value="${p.desc.replace(/\n/g,' ')}" oninput="presPartidas[${i}].desc=this.value" placeholder="Descripción..." style="text-align:left;font-size:12.5px;">
      </td>
      <td style="padding:4px 6px;text-align:center;">
        <input class="pres-input" value="${p.ud}" oninput="presPartidas[${i}].ud=this.value" style="text-align:center;width:38px;font-size:12px;">
      </td>
      <td style="padding:4px 6px;text-align:right;">
        <input class="pres-input" type="number" value="${p.qty}" min="0" step="0.01" oninput="presPartidas[${i}].qty=parseFloat(this.value)||0;presUpdateRow(${i})" style="width:52px;">
      </td>
      <td style="padding:4px 6px;text-align:right;">
        <input class="pres-input" type="number" value="${pUnitCliente.toFixed(2)}" min="0" step="0.01" oninput="presPartidas[${i}].pUnit=parseFloat(this.value)||0;presUpdateRow(${i})" style="width:72px;">
      </td>
      <td style="padding:6px 10px;text-align:right;font-weight:600;font-family:'Inter',sans-serif;font-size:12.5px;" id="prow-total-${i}">€${fmtNum(totalCliente)}</td>
      <!-- ZONA PROVEEDOR (fondo azul claro) -->
      <td style="padding:4px 6px;text-align:right;background:#F0F5FF;">
        <input class="pres-input" type="number" value="${costeUnit.toFixed(2)}" min="0" step="0.01" oninput="presPartidas[${i}].costeUnit=parseFloat(this.value)||0;presUpdateRow(${i})" style="width:72px;color:#1F6FEB;">
      </td>
      <td style="padding:6px 10px;text-align:right;background:#F0F5FF;font-family:'Inter',sans-serif;font-size:12px;color:#1F6FEB;" id="prow-totalprov-${i}">€${fmtNum(totalProv)}</td>
      <td style="padding:4px 6px;background:#F0F5FF;">
        <input class="pres-input" value="${p.proveedor||''}" oninput="presPartidas[${i}].proveedor=this.value" placeholder="Proveedor" style="width:100px;font-size:12px;color:#1F6FEB;">
      </td>
      <!-- MARGEN Y BENEFICIO (fondo morado / verde) -->
      <td style="padding:6px 10px;text-align:center;background:#F5F0FF;font-family:'Inter',sans-serif;font-size:12px;font-weight:600;color:#8B5CF6;" id="prow-pct-${i}">${pctMO.toFixed(1)}%</td>
      <td style="padding:6px 10px;text-align:right;background:#E8F7F3;font-family:'Inter',sans-serif;font-size:12px;font-weight:600;color:#0D9373;" id="prow-cliente-${i}">€${fmtNum(beneficio)}</td>
      <td style="padding:4px;text-align:center;">
        <button onclick="presDeletePartida(${i})" style="background:none;border:none;cursor:pointer;color:var(--text-3);padding:3px;border-radius:4px;">
          <svg width="11" height="11" viewBox="0 0 16 16" fill="none"><path d="M4 4l8 8M12 4l-8 8" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
        </button>
      </td>
    </tr>`;
  }).join('') + `
  <tr style="background:var(--surface-2);">
    <td colspan="9" style="padding:8px 12px;">
      <button class="btn btn-ghost btn-sm" onclick="presAddPartida()" style="font-size:12px;color:var(--accent);">
        <svg width="11" height="11" viewBox="0 0 16 16" fill="none"><path d="M8 2v12M2 8h12" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
        Añadir partida
      </button>
    </td>
  </tr>`;
  presRecalcTotales();
}

function presUpdateRow(i) {
  const p = presPartidas[i];
  const totalCliente = p.qty * p.pUnit;
  const costeUnit = p.costeUnit || 0;
  const totalProv = p.qty * costeUnit;
  const beneficio = totalCliente - totalProv;
  const pctMO = totalCliente > 0 ? (beneficio / totalCliente * 100) : 0;
  const tEl = document.getElementById('prow-total-'+i);
  const tpEl = document.getElementById('prow-totalprov-'+i);
  const pctEl = document.getElementById('prow-pct-'+i);
  const cEl = document.getElementById('prow-cliente-'+i);
  if (tEl) tEl.textContent = '€'+fmtNum(totalCliente);
  if (tpEl) tpEl.textContent = '€'+fmtNum(totalProv);
  if (pctEl) pctEl.textContent = pctMO.toFixed(1)+'%';
  if (cEl) cEl.textContent = '€'+fmtNum(beneficio);
  presRecalcTotales();
}

function presRecalcTotales() {
  const totalCliente = presPartidas.reduce((s,x) => s + x.qty * x.pUnit, 0);
  const totalCoste = presPartidas.reduce((s,x) => s + x.qty * (x.costeUnit||0), 0);
  const mo = totalCliente - totalCoste;
  const moPct = totalCliente > 0 ? (mo / totalCliente * 100) : 0;

  const set = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val; };
  set('pres-total-coste', '€'+fmtNum(totalCoste));
  set('pres-total-precio', '€'+fmtNum(totalCliente)+' (cliente) · €'+fmtNum(totalCoste)+' (prov.)');
  set('pres-total-mo-eur', '€'+fmtNum(mo));
  set('pres-total-mo-pct', fmtNum(moPct)+'%');
  set('pres-total-final', '€'+fmtNum(totalCliente));
}

function presAddPartida() {
  const nro = presPartidas.length + 1;
  presPartidas.push({ nro, desc:'', ud:'ud', qty:1, pUnit:0, margen:20, costeUnit:0, proveedor:'' });
  renderPresPartidas();
  // Focus new row description
  setTimeout(() => {
    const inputs = document.querySelectorAll('.pres-desc-input');
    if (inputs.length) inputs[inputs.length-1].focus();
  }, 50);
}

function presDeletePartida(i) {
  presPartidas.splice(i, 1);
  presPartidas.forEach((p,j) => p.nro = j+1);
  renderPresPartidas();
}

// ===== ADJUNTOS =====
window._presAdjuntos = {}; // { presKey: [ {name, size, type, url, fecha} ] }

function presAdjKey() {
  const codigo = document.getElementById('pres-codigo-display')?.textContent || 'unknown';
  return codigo;
}
function presAdjuntarArchivos(files) {
  const key = presAdjKey();
  if (!window._presAdjuntos[key]) window._presAdjuntos[key] = [];
  // Build proveedor list from current partidas for the prompt
  const proveedores = [...new Set((presPartidas||[]).map(x=>x.proveedor).filter(Boolean))];
  const provSuggestion = proveedores.length ? proveedores.join(' / ') : '';
  const provInput = provSuggestion
    ? prompt('¿A qué proveedor pertenece este documento?\nProveedores en este presupuesto: ' + provSuggestion + '\n(Deja vacío si es genérico)', proveedores[0] || '')
    : '';
  const proveedor = (provInput || '').trim();
  Array.from(files).forEach(file => {
    const url = URL.createObjectURL(file);
    const ext = file.name.split('.').pop().toLowerCase();
    const iconMap = { pdf:'📄', png:'🖼️', jpg:'🖼️', jpeg:'🖼️', eml:'📧', msg:'📧', docx:'📝', xlsx:'📊', txt:'📋' };
    const icon = iconMap[ext] || '📎';
    const kb = (file.size / 1024).toFixed(0);
    const mb = file.size > 1024*1024 ? (file.size/1024/1024).toFixed(1)+' MB' : kb+' KB';
    const fecha = new Date().toLocaleDateString('es-ES');
    const proveedores = [...new Set(presPartidas.map(p => p.proveedor).filter(Boolean))];
    const prov = proveedores.length > 0 ? proveedores.slice(0,2).join(' / ') : '';
    window._presAdjuntos[key].push({ name:file.name, size:mb, type:ext, url, icon, fecha, proveedor:prov });
  });
  renderPresAdjuntos();
  showToast(files.length + ' archivo' + (files.length > 1 ? 's' : '') + ' adjuntado' + (files.length > 1 ? 's' : ''));
}
function renderPresAdjuntos() {
  const key = presAdjKey();
  const lista = window._presAdjuntos[key] || [];
  const container = document.getElementById('pres-adjuntos-list');
  const empty = document.getElementById('pres-adjuntos-empty');
  if (!container) return;
  if (lista.length === 0) {
    if (empty) empty.style.display = 'block';
    // Remove existing file rows
    container.querySelectorAll('.adj-row').forEach(r => r.remove());
    return;
  }
  if (empty) empty.style.display = 'none';
  container.querySelectorAll('.adj-row').forEach(r => r.remove());
  lista.forEach((f, i) => {
    const row = document.createElement('div');
    row.className = 'adj-row';
    row.style.cssText = 'display:flex;align-items:center;gap:12px;padding:11px 18px;border-bottom:1px solid var(--border);';
    const typeColor = { pdf:'var(--danger)', png:'#8B5CF6', jpg:'#8B5CF6', jpeg:'#8B5CF6', eml:'var(--accent)', msg:'var(--accent)', docx:'#1F6FEB', xlsx:'var(--accent-2)', txt:'var(--text-3)' };
    const col = typeColor[f.type] || 'var(--text-3)';
    row.innerHTML = `
      <div style="width:34px;height:34px;border-radius:7px;background:var(--surface-2);border:1px solid var(--border);display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:16px;">${f.icon}</div>
      <div style="flex:1;min-width:0;">
        <div style="display:flex;align-items:center;gap:8px;">
          <div style="font-size:13px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${f.name}</div>
          ${f.proveedor ? `<span style="font-size:10px;background:var(--accent-light);color:var(--accent);padding:1px 7px;border-radius:10px;white-space:nowrap;flex-shrink:0;">${f.proveedor}</span>` : ''}
        </div>
        <div style="font-size:11px;color:var(--text-3);margin-top:2px;">${f.size} · <span style="font-weight:600;color:${col};text-transform:uppercase;">${f.type}</span>${f.proveedor ? ' · <span style="background:#EEF4FF;color:#1F6FEB;padding:1px 5px;border-radius:3px;font-weight:500;">'+f.proveedor+'</span>' : ''} · Subido ${f.fecha}</div>
      </div>
      <a href="${f.url}" download="${f.name}" style="color:var(--accent);font-size:12px;text-decoration:none;" class="btn btn-ghost btn-sm">Descargar</a>
      <button onclick="presEliminarAdjunto(${i})" style="background:none;border:none;cursor:pointer;color:var(--text-3);padding:4px;border-radius:4px;" title="Eliminar">
        <svg width="13" height="13" viewBox="0 0 16 16" fill="none"><path d="M4 4l8 8M12 4l-8 8" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
      </button>`;
    container.appendChild(row);
  });
}
function presEliminarAdjunto(i) {
  const key = presAdjKey();
  if (window._presAdjuntos[key]) {
    window._presAdjuntos[key].splice(i, 1);
    renderPresAdjuntos();
  }
}
// Re-render adjuntos when opening a presupuesto
const _origPresVerDetalle = presVerDetalle;
presVerDetalle = function(i) {
  _origPresVerDetalle(i);
  setTimeout(renderPresAdjuntos, 50);
};

